package com.grit.liferecorder.data.local.dao
import androidx.room.*; import com.grit.liferecorder.data.local.entity.*; import kotlinx.coroutines.flow.Flow

@Dao interface CategoryDao { @Query("SELECT * FROM categories ORDER BY name") fun observeAll():Flow<List<CategoryEntity>>; @Query("SELECT COUNT(*) FROM categories") suspend fun count():Int; @Insert suspend fun insert(entity:CategoryEntity):Long; @Insert suspend fun insertAll(items:List<CategoryEntity>); @Update suspend fun update(entity:CategoryEntity); @Delete suspend fun delete(entity:CategoryEntity) }
@Dao interface ProjectDao { @Query("SELECT * FROM projects ORDER BY isActive DESC, name") fun observeAll():Flow<List<ProjectEntity>>; @Insert suspend fun insert(entity:ProjectEntity):Long; @Update suspend fun update(entity:ProjectEntity); @Delete suspend fun delete(entity:ProjectEntity) }
@Dao interface TaskDao { @Query("SELECT * FROM tasks ORDER BY CASE status WHEN 'Open' THEN 0 ELSE 1 END, completeByDate IS NULL, completeByDate, createdAt DESC") fun observeAll():Flow<List<TaskEntity>>; @Query("SELECT * FROM tasks WHERE completeByDate=:date OR (completedAt IS NOT NULL AND completedAt BETWEEN :start AND :end) ORDER BY createdAt DESC") fun observeForDate(date:String,start:Long,end:Long):Flow<List<TaskEntity>>; @Query("SELECT * FROM tasks WHERE completeByDate BETWEEN :start AND :end OR (completedAt BETWEEN :startMillis AND :endMillis)") fun observeBetween(start:String,end:String,startMillis:Long,endMillis:Long):Flow<List<TaskEntity>>; @Query("SELECT * FROM tasks") fun observeStats():Flow<List<TaskEntity>>; @Insert suspend fun insert(entity:TaskEntity):Long; @Update suspend fun update(entity:TaskEntity); @Delete suspend fun delete(entity:TaskEntity); @Query("SELECT * FROM tasks WHERE id=:id") suspend fun get(id:Long):TaskEntity? }
@Dao interface TrackedActionDao { @Query("SELECT * FROM tracked_actions ORDER BY isActive DESC, name") fun observeAll():Flow<List<TrackedActionEntity>>; @Insert suspend fun insert(entity:TrackedActionEntity):Long; @Update suspend fun update(entity:TrackedActionEntity); @Delete suspend fun delete(entity:TrackedActionEntity); @Query("SELECT * FROM tracked_actions WHERE id=:id") suspend fun get(id:Long):TrackedActionEntity? }
@Dao interface ActionLogDao { @Query("SELECT * FROM action_logs ORDER BY loggedAt DESC") fun observeAll():Flow<List<ActionLogEntity>>; @Query("SELECT * FROM action_logs WHERE localDate=:date ORDER BY loggedAt") fun observeForDate(date:String):Flow<List<ActionLogEntity>>; @Query("SELECT * FROM action_logs WHERE localDate BETWEEN :start AND :end") fun observeBetween(start:String,end:String):Flow<List<ActionLogEntity>>; @Query("SELECT * FROM action_logs WHERE trackedActionId=:id ORDER BY loggedAt DESC") fun observeForAction(id:Long):Flow<List<ActionLogEntity>>; @Insert suspend fun insert(entity:ActionLogEntity):Long; @Update suspend fun update(entity:ActionLogEntity); @Delete suspend fun delete(entity:ActionLogEntity) }
@Dao interface RoutineDao { @Query("SELECT * FROM routines ORDER BY isActive DESC, name") fun observeAll():Flow<List<RoutineEntity>>; @Query("SELECT * FROM routines WHERE isActive=1") suspend fun active():List<RoutineEntity>; @Insert suspend fun insert(entity:RoutineEntity):Long; @Update suspend fun update(entity:RoutineEntity); @Delete suspend fun delete(entity:RoutineEntity); @Query("SELECT * FROM routines WHERE id=:id") suspend fun get(id:Long):RoutineEntity? }
@Dao interface RoutineStepDao { @Query("SELECT * FROM routine_steps WHERE routineId=:routineId ORDER BY stepOrder") fun observeForRoutine(routineId:Long):Flow<List<RoutineStepEntity>>; @Query("SELECT * FROM routine_steps WHERE routineId=:routineId ORDER BY stepOrder") suspend fun getForRoutine(routineId:Long):List<RoutineStepEntity>; @Insert suspend fun insert(entity:RoutineStepEntity):Long; @Insert suspend fun insertAll(items:List<RoutineStepEntity>); @Update suspend fun update(entity:RoutineStepEntity); @Delete suspend fun delete(entity:RoutineStepEntity); @Query("DELETE FROM routine_steps WHERE routineId=:routineId") suspend fun deleteForRoutine(routineId:Long) }
@Dao interface RoutineOccurrenceDao { @Query("SELECT * FROM routine_occurrences ORDER BY localDate DESC") fun observeAll():Flow<List<RoutineOccurrenceEntity>>; @Query("SELECT * FROM routine_occurrences WHERE localDate=:date") fun observeForDate(date:String):Flow<List<RoutineOccurrenceEntity>>; @Query("SELECT * FROM routine_occurrences WHERE localDate BETWEEN :start AND :end") fun observeBetween(start:String,end:String):Flow<List<RoutineOccurrenceEntity>>; @Query("SELECT * FROM routine_occurrences WHERE routineId=:routineId AND localDate=:date") suspend fun get(routineId:Long,date:String):RoutineOccurrenceEntity?; @Insert(onConflict=OnConflictStrategy.REPLACE) suspend fun upsert(entity:RoutineOccurrenceEntity):Long; @Update suspend fun update(entity:RoutineOccurrenceEntity) }
@Dao interface JournalDao { @Query("SELECT * FROM journal_entries ORDER BY localDate DESC") fun observeAll():Flow<List<JournalEntryEntity>>; @Query("SELECT * FROM journal_entries WHERE localDate=:date") fun observeForDate(date:String):Flow<JournalEntryEntity?>; @Query("SELECT * FROM journal_entries WHERE localDate BETWEEN :start AND :end") fun observeBetween(start:String,end:String):Flow<List<JournalEntryEntity>>; @Insert(onConflict=OnConflictStrategy.REPLACE) suspend fun upsert(entity:JournalEntryEntity):Long; @Delete suspend fun delete(entity:JournalEntryEntity) }
